            const safeZ = Number.isFinite(z) ? z : startZoom;
            setZoom(Math.max(MIN_UNIVERSE_ZOOM, safeZ));

            if (raw < 1) {
                flyAnimRef.current = requestAnimationFrame(animate);
            } else {
                flyAnimRef.current = null;
                isFlying.current = false;
                if (onComplete) onComplete();
            }
        };

        flyAnimRef.current = requestAnimationFrame(animate);
    }, []); // stable — reads from refs

    return {
        stageRef,
        stageSize,
        camera,
        zoom,
        isDragging,
        centerWorld,
        getLayerProps,
        getViewportBounds,
        stageEvents,
        flyTo,
        jumpTo,
        isFlying,
    };
};

export default useUniverseCamera;

