  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import { Stage } from 'react-konva';
  3→import { useNavigate } from 'react-router-dom';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { getUniversePosts, getUserData } from '../../../API/Api';
  6→import supabase from '../../utils/supabaseClient';
  7→import useUniverseCamera from './hooks/useUniverseCamera';
  8→import useCosmicGravity from './hooks/useCosmicGravity';
  9→import DeepSpaceLayer from './layers/DeepSpaceLayer';
 10→import MidGalaxyLayer from './layers/MidGalaxyLayer';
 11→import NebulaLayer from './layers/NebulaLayer';
 12→import InteractiveLayer from './layers/InteractiveLayer';
 13→import WormholeLayer from './layers/WormholeLayer';
 14→import UniverseMinimap from './components/UniverseMinimap';
 15→import { extractSnippet, MIN_UNIVERSE_ZOOM, userHomeCoords } from './utils/starUtils';
 16→import {
 17→    buildSectorIndex,
 18→    computeGalaxyCentroids,
 19→    computeSectorKey,
 20→    getNeighborSectorKeys,
 21→} from './utils/cosmicPhysics';
 22→import { handleClickProfile } from '../../../helpers/handleClicks';
 23→import styles from './Universe.module.css';
 24→
 25→const SECTOR_SIZE = 2000;
 26→const ENABLE_SETTLED_RPC_SAVE = import.meta.env.VITE_ENABLE_UNIVERSE_SETTLE_SAVE === 'true';
 27→
 28→const Universe = () => {
 29→    const navigate = useNavigate();
 30→    const { user } = useAuth();
 31→    const userId = user?.userData?.[0]?.id || null;
 32→
 33→    const fetchDebounceRef = useRef(null);
 34→    const settleDebounceRef = useRef(null);
 35→    const lastSettledPayloadRef = useRef('');
 36→    const initialFetchResolvedRef = useRef(false);
 37→    const hasAutoFocusedOwnGalaxyRef = useRef(false);
 38→    const ownGalaxyLookupStartedRef = useRef(false);
 39→
 40→    const [posts, setPosts] = useState(new Map());
 41→    const [selectedPost, setSelectedPost] = useState(null);
 42→    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
 43→    const [galaxyProfile, setGalaxyProfile] = useState(null);
 44→    const [pulsingId, setPulsingId] = useState(null);
 45→    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
 46→    const [isInitialLoading, setIsInitialLoading] = useState(true);
 47→    const [ownGalaxyTarget, setOwnGalaxyTarget] = useState(null);
 48→    const [wormholes, setWormholes] = useState([]);
 49→    const [isWarping, setIsWarping] = useState(false);
 50→
 51→    // Gravity data from server (fallback paths when embeddings are unavailable in payload)
 52→    const [centroids, setCentroids] = useState([]);
 53→    const [galaxyEdges, setGalaxyEdges] = useState([]);
 54→    const [similarPairs, setSimilarPairs] = useState([]);
 55→    const [starPulls, setStarPulls] = useState([]);
 56→
 57→    const {
 58→        stageRef, stageSize, camera, zoom, isDragging, centerWorld,
 59→        getLayerProps, getViewportBounds, stageEvents, flyTo, jumpTo, isFlying,
 60→    } = useUniverseCamera(userId, hasOwnPosts);
 61→
 62→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
 63→    const showTitles = zoom > 0.5;
 64→
 65→    // Sector partitioning for scalable local gravity math.
 66→    const postSectorIndex = useMemo(() => (
 67→        buildSectorIndex(
 68→            postArray,
 69→            (post) => ({
 70→                x: post?.display_x ?? post?.universe_x,
 71→                y: post?.display_y ?? post?.universe_y,
 72→            }),
 73→            SECTOR_SIZE
 74→        )
 75→    ), [postArray]);
 76→
 77→    const centerSectorKey = useMemo(
 78→        () => computeSectorKey(centerWorld.x, centerWorld.y, SECTOR_SIZE),
 79→        [centerWorld.x, centerWorld.y]
 80→    );
 81→
 82→    const activeSectorKeys = useMemo(
 83→        () => new Set(getNeighborSectorKeys(centerSectorKey)),
 84→        [centerSectorKey]
 85→    );
 86→
 87→    const activePosts = useMemo(() => {
 88→        if (activeSectorKeys.size === 0) return postArray;
 89→
 90→        const next = [];
 91→        for (const key of activeSectorKeys) {
 92→            const bucket = postSectorIndex.get(key);
 93→            if (bucket?.length) next.push(...bucket);
 94→        }
 95→        return next;
 96→    }, [postArray, postSectorIndex, activeSectorKeys]);
 97→
 98→    const activePostIds = useMemo(() => {
 99→        const ids = new Set();
100→        for (const post of activePosts) {
101→            if (post?.id) ids.add(post.id);
102→        }
103→        return ids;
104→    }, [activePosts]);
105→
106→    const { centroidByUser } = useMemo(
107→        () => computeGalaxyCentroids(postArray),
108→        [postArray]
109→    );
110→
111→    // ── Hash-based galaxies (STARTING positions — always from hash) ──
112→    const hashGalaxies = useMemo(() => {
113→        const seen = new Map();
114→        for (const post of postArray) {
115→            const uid = post.users?.id ?? post.user_id;
116→            if (!uid || seen.has(uid)) continue;
117→            const hash = userHomeCoords(uid);
118→            seen.set(uid, {
119→                userId: uid,
120→                name: post.users?.name ?? post.user_name ?? 'Anonymous',
121→                x: hash.x,
122→                y: hash.y,
123→            });
124→        }
125→        return Array.from(seen.values());
126→    }, [postArray]);
127→
128→    // ── Centroid targets (WHERE galaxies should fly TO) ──────────────
129→    const centroidTargets = useMemo(() => {
130→        const map = new Map();
131→        for (const c of centroids) {
132→            if (c.galaxy_x != null && c.galaxy_y != null) {
133→                map.set(c.user_id, { x: c.galaxy_x, y: c.galaxy_y });
134→            }
135→        }
136→        return map;
137→    }, [centroids]);
138→
139→    // ── Gravity hook: animates galaxies + computes star pull offsets ─
140→    const {
141→        galaxyPositions,
142→        starPullOffsets,
143→        isSettled,
144→        galaxyEdges: effectiveGalaxyEdges,
145→        hasEmbeddingGravity,
146→    } = useCosmicGravity({
147→        galaxies: hashGalaxies,
148→        centroidTargets,
149→        edges: galaxyEdges,
150→        posts: postArray,
151→        starPulls,
152→        centroidByUser,
153→        activeSectorKeys,
154→        activePostIds,
155→        sectorSize: SECTOR_SIZE,
156→    });
157→
158→    // ── Render galaxies = hash galaxies with animated positions ──────
159→    const galaxies = useMemo(() => {
160→        return hashGalaxies.map(g => {
161→            const animated = galaxyPositions.get(g.userId);
162→            return animated ? { ...g, x: animated.x, y: animated.y } : g;
163→        });
164→    }, [hashGalaxies, galaxyPositions]);
165→
166→    // Home position for distance tracker — same resolution as auto-focus.
167→    const homePosition = useMemo(() => {
168→        if (!userId) return { x: 0, y: 0 };
169→        const ownGalaxy = galaxies.find((g) => g.userId === userId);
170→        if (ownGalaxy) return { x: ownGalaxy.x, y: ownGalaxy.y };
171→        return centroidTargets.get(userId) || ownGalaxyTarget || { x: 0, y: 0 };
172→    }, [userId, galaxies, centroidTargets, ownGalaxyTarget]);
173→
174→    const getComputedStarPosition = useCallback((post) => {
175→        if (!post) return null;
176→
177→        const uid = post.users?.id ?? post.user_id;
178→        const hashGal = userHomeCoords(uid);
179→        const animGal = galaxyPositions.get(uid);
180→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
181→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
182→        const pull = starPullOffsets.get(post.id);
183→
184→        const baseX = post.universe_x ?? post.display_x;
185→        const baseY = post.universe_y ?? post.display_y;
186→        if (baseX == null || baseY == null) return null;
187→
188→        return {
189→            x: baseX + galDx + (pull?.dx ?? 0),
190→            y: baseY + galDy + (pull?.dy ?? 0),
191→        };
192→    }, [galaxyPositions, starPullOffsets]);
193→
194→    // Resolve logged-in user's galaxy target independently from viewport data.
195→    useEffect(() => {
196→        if (!userId) return;
197→        if (ownGalaxyLookupStartedRef.current) return;
198→
199→        ownGalaxyLookupStartedRef.current = true;
200→        let cancelled = false;
201→
202→        const resolveOwnGalaxyTarget = async () => {
203→            try {
204→                const { data, error } = await supabase
205→                    .from('galaxy_centroids')
206→                    .select('galaxy_x, galaxy_y')
207→                    .eq('user_id', userId)
208→                    .maybeSingle();
209→
210→                if (cancelled) return;
211→
212→                if (!error && data?.galaxy_x != null && data?.galaxy_y != null) {
213→                    setOwnGalaxyTarget({ x: data.galaxy_x, y: data.galaxy_y });
214→                    setHasOwnPosts(true);
215→                    return;
216→                }
217→            } catch (err) {
218→                console.warn('[universe] own centroid lookup failed:', err?.message || err);
219→            }
220→
221→            if (!cancelled) {
222→                setOwnGalaxyTarget(userHomeCoords(userId));
223→            }
224→        };
225→
226→        resolveOwnGalaxyTarget();
227→
228→        return () => {
229→            cancelled = true;
230→        };
231→    }, [userId]);
232→
233→    // One-time wormhole fetch on mount
234→    useEffect(() => {
235→        let cancelled = false;
236→
237→        const fetchWormholes = async () => {
238→            try {
239→                const { data, error } = await supabase.rpc('find_wormhole_pairs', {
240→                    similarity_threshold: 0.7,
241→                    min_distance: 0,
242→                    max_pairs: 30,
243→                });
244→                if (cancelled) return;
245→                if (error) {
246→                    console.warn('[universe] wormhole fetch error:', error.message);
247→                    return;
248→                }
249→                console.log('[universe] wormhole pairs:', data);
250→                if (Array.isArray(data) && data.length > 0) {
251→                    setWormholes(data);
252→                }
253→            } catch (err) {
254→                if (!cancelled) {
255→                    console.warn('[universe] wormhole fetch failed:', err?.message || err);
256→                }
257→            }
258→        };
259→
260→        fetchWormholes();
261→        return () => { cancelled = true; };
262→    }, []);
263→
264→    // Debounced fetch on camera/zoom change
265→    useEffect(() => {
266→        if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
267→
268→        fetchDebounceRef.current = setTimeout(async () => {
269→            const bounds = getViewportBounds();
270→            try {
271→                const result = await getUniversePosts(
272→                    bounds.minX,
273→                    bounds.maxX,
274→                    bounds.minY,
275→                    bounds.maxY,
276→                    200
277→                );
278→                if (result?.data) {
279→                    setPosts(prev => {
280→                        const next = new Map(prev);
281→                        for (const post of result.data) {
282→                            next.set(post.id, post);
283→                        }
284→                        return next;
285→                    });
286→                    if (userId && hasOwnPosts !== true) {
287→                        const ownsAny = result.data.some(p =>
288→                            (p.users?.id ?? p.user_id) === userId
289→                        );
290→                        if (ownsAny) setHasOwnPosts(true);
291→                    }
292→                }
293→                // Keep server gravity data as fallback when embeddings are absent in payload.
294→                setCentroids(Array.isArray(result?.centroids) ? result.centroids : []);
295→                setGalaxyEdges(Array.isArray(result?.edges) ? result.edges : []);
296→                setSimilarPairs(Array.isArray(result?.similarPairs) ? result.similarPairs : []);
297→                setStarPulls(Array.isArray(result?.starPulls) ? result.starPulls : []);
298→            } catch (err) {
299→                console.error('Failed to fetch universe posts:', err);
300→            } finally {
301→                if (!initialFetchResolvedRef.current) {
302→                    initialFetchResolvedRef.current = true;
303→                    setIsInitialLoading(false);
304→                }
305→            }
306→        }, 400);
307→
308→        return () => {
309→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
310→        };
311→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
312→
313→    const handleStarClick = useCallback((post) => {
314→        if (isFlying.current) return;
315→        setSelectedPost(post);
316→        setSelectedGalaxy(null);
317→        setGalaxyProfile(null);
318→
319→        const position = getComputedStarPosition(post);
320→        if (!position) return;
321→
322→        flyTo(position.x, position.y, 1.2, () => {
323→            setPulsingId(post.id);
324→            setTimeout(() => setPulsingId(null), 700);
325→        });
326→    }, [flyTo, getComputedStarPosition, isFlying]);
327→
328→    const handleGalaxyClick = useCallback(async (galaxy) => {
329→        if (isFlying.current) return;
330→        setSelectedGalaxy(galaxy);
331→        setSelectedPost(null);
332→        setGalaxyProfile(null);
333→        flyTo(galaxy.x, galaxy.y, 0.8);
334→
335→        try {
336→            const data = await getUserData(galaxy.userId);
337→            const profile = data?.userData?.[0] || null;
338→            setGalaxyProfile(profile);
339→        } catch (err) {
340→            console.error('Failed to fetch galaxy profile:', err);
341→        }
342→    }, [flyTo, isFlying]);
343→
344→    const handleReadPost = useCallback(() => {
345→        if (!selectedPost) return;
346→        navigate(`/home/post/${selectedPost.id}`);
347→    }, [selectedPost, navigate]);
348→
349→    const handleMinimapNavigate = useCallback((worldX, worldY, mode = 'fly') => {
350→        if (mode === 'drag') {
351→            jumpTo(worldX, worldY);
352→            return;
353→        }
354→        flyTo(worldX, worldY, zoom);
355→    }, [flyTo, jumpTo, zoom]);
356→
357→    // Enrich wormhole positions with live gravity-computed post coords
358→    const enrichedWormholes = useMemo(() => {
359→        return wormholes.map(wh => {
360→            const postA = posts.get(wh.post_a);
361→            const postB = posts.get(wh.post_b);
362→            const posA = postA ? getComputedStarPosition(postA) : null;
363→            const posB = postB ? getComputedStarPosition(postB) : null;
364→            return {
365→                ...wh,
366→                a_x: posA?.x ?? wh.a_x,
367→                a_y: posA?.y ?? wh.a_y,
368→                b_x: posB?.x ?? wh.b_x,
369→                b_y: posB?.y ?? wh.b_y,
370→            };
371→        });
372→    }, [wormholes, posts, getComputedStarPosition]);
373→
374→    // Find wormhole connection for a given post (if any)
375→    const getWormholeForPost = useCallback((postId) => {
376→        if (!postId || enrichedWormholes.length === 0) return null;
377→        for (const wh of enrichedWormholes) {
378→            if (wh.post_a === postId) return { wormhole: wh, side: 'a', targetTitle: wh.b_title };
379→            if (wh.post_b === postId) return { wormhole: wh, side: 'b', targetTitle: wh.a_title };
380→        }
381→        return null;
382→    }, [enrichedWormholes]);
383→
384→    const handleWormholeTravel = useCallback(() => {
385→        if (!selectedPost || isFlying.current) return;
386→        const match = getWormholeForPost(selectedPost.id);
387→        if (!match) return;
388→        const { wormhole, side } = match;
389→        const targetX = side === 'a' ? wormhole.b_x : wormhole.a_x;
390→        const targetY = side === 'a' ? wormhole.b_y : wormhole.a_y;
391→        setSelectedPost(null);
392→        setIsWarping(true);
393→        flyTo(targetX, targetY, zoom, () => setIsWarping(false));
394→    }, [selectedPost, getWormholeForPost, flyTo, isFlying, zoom]);
395→
396→    // One-time auto focus after first payload is loaded.
397→    useEffect(() => {
398→        if (!userId) return;
399→        if (isInitialLoading) return;
400→        if (hasAutoFocusedOwnGalaxyRef.current) return;
401→
402→        const ownGalaxy = galaxies.find((galaxy) => galaxy.userId === userId);
403→        const target = ownGalaxy
404→            ? { x: ownGalaxy.x, y: ownGalaxy.y }
405→            : (centroidTargets.get(userId) || ownGalaxyTarget);
406→
407→        // Wait until we have a concrete own target; fallback is resolved asynchronously.
408→        if (!target) return;
409→
410→        hasAutoFocusedOwnGalaxyRef.current = true;
411→        flyTo(target.x, target.y, MIN_UNIVERSE_ZOOM);
412→    }, [userId, isInitialLoading, galaxies, centroidTargets, ownGalaxyTarget, flyTo]);
413→
414→    const settledPayload = useMemo(() => {
415→        if (!isSettled || activePosts.length === 0) return [];
416→
417→        const payload = [];
418→        for (const post of activePosts) {
419→            if (!post?.id) continue;
420→            const pos = getComputedStarPosition(post);
421→            if (!pos || !Number.isFinite(pos.x) || !Number.isFinite(pos.y)) continue;
422→
423→            payload.push({
424→                post_id: post.id,
425→                settled_x: Math.round(pos.x * 100) / 100,
426→                settled_y: Math.round(pos.y * 100) / 100,
427→            });
428→        }
429→
430→        payload.sort((a, b) => String(a.post_id).localeCompare(String(b.post_id)));
431→        return payload;
432→    }, [activePosts, getComputedStarPosition, isSettled]);
433→
434→    // Placeholder persistence hook: debounced Supabase RPC for settled positions.
435→    useEffect(() => {
436→        if (!ENABLE_SETTLED_RPC_SAVE) return;
437→        if (!isSettled || settledPayload.length === 0) return;
438→
439→        const signature = JSON.stringify(settledPayload);
440→        if (signature === lastSettledPayloadRef.current) return;
441→
442→        if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
443→        settleDebounceRef.current = setTimeout(async () => {
444→            lastSettledPayloadRef.current = signature;
445→            try {
446→                const { error } = await supabase.rpc('save_universe_settled_positions', {
447→                    positions_payload: settledPayload,
448→                });
449→                if (error) {
